};

class CommandPalette {
private:
    HWND hwnd_;
    HWND listbox_;
    HWND edit_;
    std::vector<CommandItem> commands_;
    std::vector<CommandItem> filtered_commands_;
    std::function<void(const std::string&)> execute_callback_;
    
public:
    CommandPalette(HWND parent);
    ~CommandPalette();
    
    void Show();
    void Hide();
    bool IsVisible() const;
    
    void AddCommand(const CommandItem& cmd);
    void RemoveCommand(const std::string& name);
    void ClearCommands();
    
    void UpdateFilter(const std::string& filter);
    void ExecuteSelected();
    void MoveSelection(int delta);
    
    void OnKeyDown(WPARAM wParam);
