### **command_palette.cpp**
```cpp
#include "command_palette.h"
#include <commctrl.h>
#include <algorithm>

std::unique_ptr<CommandPalette> g_command_palette;

CommandPalette::CommandPalette(HWND parent) : hwnd_(nullptr), listbox_(nullptr), edit_(nullptr) {
    CreateControls();
    CenterWindow();
}

CommandPalette::~CommandPalette() {
    if (hwnd_) DestroyWindow(hwnd_);
}

void CommandPalette::CreateControls() {
    // Create window
    hwnd_ = CreateWindowExW(
        WS_EX_TOPMOST | WS_EX_TOOLWINDOW,
        L"STATIC",
        L"Command Palette",
        WS_POPUP | WS_BORDER | WS_CAPTION,
        0, 0, 600, 400,
        nullptr,
        nullptr,
        GetModuleHandle(nullptr),
        nullptr
    );
    
    // Create edit control for filtering
    edit_ = CreateWindowExW(
        WS_EX_CLIENTEDGE,
        L"EDIT",
        L"",
        WS_CHILD | WS_VISIBLE | ES_AUTOHSCROLL,
        10, 10, 580, 30,
        hwnd_,
        nullptr,
        GetModuleHandle(nullptr),
        nullptr
    );
    
    // Create listbox for commands
    listbox_ = CreateWindowExW(
        WS_EX_CLIENTEDGE,
        L"LISTBOX",
        nullptr,
        WS_CHILD | WS_VISIBLE | LBS_NOTIFY | WS_VSCROLL,
        10, 50, 580, 340,
        hwnd_,
        nullptr,
        GetModuleHandle(nullptr),
        nullptr
    );
    
    // Set fonts
    HFONT hFont = CreateFontW(16, 0, 0, 0, FW_NORMAL, FALSE, FALSE, FALSE,
        DEFAULT_CHARSET, OUT_DEFAULT_PRECIS, CLIP_DEFAULT_PRECIS,
        CLEARTYPE_QUALITY, DEFAULT_PITCH | FF_DONTCARE, L"Consolas");
    
    SendMessageW(edit_, WM_SETFONT, (WPARAM)hFont, TRUE);
    SendMessageW(listbox_, WM_SETFONT, (WPARAM)hFont, TRUE);
}

void CommandPalette::Show() {
    CenterWindow();
    ShowWindow(hwnd_, SW_SHOW);
    SetFocus(edit_);
    UpdateListBox();
}

void CommandPalette::Hide() {
    ShowWindow(hwnd_, SW_HIDE);
}

bool CommandPalette::IsVisible() const {
    return IsWindowVisible(hwnd_);
}

void CommandPalette::AddCommand(const CommandItem& cmd) {
    commands_.push_back(cmd);
    filtered_commands_ = commands_;
    UpdateListBox();
}

void CommandPalette::RemoveCommand(const std::string& name) {
    commands_.erase(
        std::remove_if(commands_.begin(), commands_.end(),
            [&name](const CommandItem& cmd) { return cmd.name == name; }),
        commands_.end()
    );
    filtered_commands_ = commands_;
    UpdateListBox();
}

void CommandPalette::ClearCommands() {
    commands_.clear();
    filtered_commands_.clear();
    UpdateListBox();
}

void CommandPalette::UpdateFilter(const std::string& filter) {
    filtered_commands_.clear();
    
    std::string lower_filter = filter;
    std::transform(lower_filter.begin(), lower_filter.end(), lower_filter.begin(), ::tolower);
    
    for (const auto& cmd : commands_) {
        std::string lower_name = cmd.name;
        std::string lower_desc = cmd.description;
        std::transform(lower_name.begin(), lower_name.end(), lower_name.begin(), ::tolower);
        std::transform(lower_desc.begin(), lower_desc.end(), lower_desc.begin(), ::tolower);
        
        if (lower_name.find(lower_filter) != std::string::npos ||
            lower_desc.find(lower_filter) != std::string::npos ||
            cmd.category.find(lower_filter) != std::string::npos) {
            filtered_commands_.push_back(cmd);
        }
    }
    
    UpdateListBox();
}

void CommandPalette::UpdateListBox() {
    SendMessageW(listbox_, LB_RESETCONTENT, 0, 0);
    
    for (const auto& cmd : filtered_commands_) {
        std::wstring display = std::wstring(cmd.name.begin(), cmd.name.end()) + L" - " +
                              std::wstring(cmd.description.begin(), cmd.description.end());
        SendMessageW(listbox_, LB_ADDSTRING, 0, (LPARAM)display.c_str());
    }
    
    if (!filtered_commands_.empty()) {
        SendMessageW(listbox_, LB_SETCURSEL, 0, 0);
    }
}

void CommandPalette::ExecuteSelected() {
    int sel = SendMessageW(listbox_, LB_GETCURSEL, 0, 0);
    if (sel >= 0 && sel < filtered_commands_.size()) {
        filtered_commands_[sel].execute();
        Hide();
    }
}

void CommandPalette::MoveSelection(int delta) {
    int count = SendMessageW(listbox_, LB_GETCOUNT, 0, 0);
    if (count == 0) return;
    
    int sel = SendMessageW(listbox_, LB_GETCURSEL, 0, 0);
    int new_sel = sel + delta;
    
    if (new_sel < 0) new_sel = 0;
    if (new_sel >= count) new_sel = count - 1;
    
    SendMessageW(listbox_, LB_SETCURSEL, new_sel, 0);
}

void CommandPalette::CenterWindow() {
    RECT parent_rect;
    GetWindowRect(GetParent(hwnd_), &parent_rect);
    
    int width = 600;
    int height = 400;
    int x = parent_rect.left + (parent_rect.right - parent_rect.left - width) / 2;
    int y = parent_rect.top + (parent_rect.bottom - parent_rect.top - height) / 2;
    
    SetWindowPos(hwnd_, nullptr, x, y, width, height, SWP_NOZORDER);
}

void CommandPalette::OnKeyDown(WPARAM wParam) {
    switch (wParam) {
        case VK_RETURN:
            ExecuteSelected();
            break;
        case VK_ESCAPE:
            Hide();
            break;
        case VK_DOWN:
            MoveSelection(1);
            break;
        case VK_UP:
            MoveSelection(-1);
            break;
    }
}

void CommandPalette::OnEditChange() {
    wchar_t buffer[256];
    GetWindowTextW(edit_, buffer, 256);
    std::string filter = std::string(buffer, buffer + wcslen(buffer));
    UpdateFilter(filter);
}
