### **interactive_shell.h**
```cpp
#pragma once
#include <string>
#include <thread>
#include <atomic>
#include <functional>
#include <memory>

class AgenticEngine;
class MemoryManager;

class InteractiveShell {
private:
    std::atomic<bool> running_;
    std::thread shell_thread_;
    AgenticEngine* agent_;
    MemoryManager* memory_;
    std::function<void(const std::string&)> output_callback_;
    std::function<void(const std::string&)> input_callback_;
    bool cli_mode_;
    
public:
    InteractiveShell(bool cli_mode = true);
    ~InteractiveShell();
    
    void Start(AgenticEngine* agent, MemoryManager* memory,
               std::function<void(const std::string&)> output_cb,
               std::function<void(const std::string&)> input_cb = nullptr);
    void Stop();
    
    void SendInput(const std::string& input);
    bool IsRunning() const { return running_; }
    
    // Command processing
    void ProcessCommand(const std::string& input);
    std::string GetPrompt() const;
    
    // Help system
    std::string GetHelp() const;
    std::string GetPluginHelp() const;
    
private:
    void RunShell();
    void ProcessRegularInput(const std::string& input);
    void DisplayWelcome();
};

// Global shell instance
extern std::unique_ptr<InteractiveShell> g_shell;
```

### **interactive_shell.cpp**
```cpp
#include "interactive_shell.h"
#include "agentic_engine.h"
#include "memory_manager.h"
#include "vsix_loader.h"
#include <iostream>
#include <sstream>
#include <algorithm>

std::unique_ptr<InteractiveShell> g_shell;

InteractiveShell::InteractiveShell(bool cli_mode) 
    : running_(false), agent_(nullptr), memory_(nullptr), cli_mode_(cli_mode) {}

InteractiveShell::~InteractiveShell() {
    Stop();
}

void InteractiveShell::Start(AgenticEngine* agent, MemoryManager* memory,
                            std::function<void(const std::string&)> output_cb,
                            std::function<void(const std::string&)> input_cb) {
    agent_ = agent;
    memory_ = memory;
    output_callback_ = output_cb;
    input_callback_ = input_cb;
    running_ = true;
    
    DisplayWelcome();
    
    if (cli_mode_) {
        shell_thread_ = std::thread([this]() { RunShell(); });
    }
}

