void InteractiveShell::ProcessCommand(const std::string& input) {
    if (input.empty()) return;
    
    // Check for plugin commands first
    if (input.rfind("!plugin ", 0) == 0) {
        ProcessPluginCommand(input.substr(8));
        return;
    }
    
    // Check for memory commands
    if (input.rfind("!memory ", 0) == 0) {
        ProcessMemoryCommand(input.substr(8));
        return;
    }
    
    // Process agentic commands
    if (input.rfind("/plan ", 0) == 0) {
        std::string task = input.substr(6);
        std::string result = agent_->planTask(task).dump(2);
        if (output_callback_) output_callback_("[Plan]\n" + result + "\n");
    }
    else if (input.rfind("/react-server ", 0) == 0) {
        std::string project = input.substr(14);
        bool success = RawrXD::ReactServerGenerator::Generate(project, project);
        if (output_callback_) {
            output_callback_(success ? "React server generated successfully\n" : "Failed to generate\n");
        }
    }
    else if (input.rfind("/bugreport ", 0) == 0) {
        std::string file = input.substr(11);
        std::string result = agent_->bugReport(file, "Static analysis");
        if (output_callback_) output_callback_("[Bug Report]\n" + result + "\n");
    }
    else if (input.rfind("/suggest ", 0) == 0) {
        std::string code = input.substr(9);
        std::string result = agent_->codeSuggestions(code);
        if (output_callback_) output_callback_("[Suggestions]\n" + result + "\n");
    }
    else if (input.rfind("/hotpatch ", 0) == 0) {
        // Parse: /hotpatch file old new
        std::istringstream iss(input.substr(10));
        std::string file, old, new_str;
        iss >> file >> old >> new_str;
        
        // Apply hotpatch
        std::string result = ApplyHotPatch(file, old, new_str);
        if (output_callback_) output_callback_(result + "\n");
    }
    else if (input.rfind("/maxmode ", 0) == 0) {
        std::string arg = input.substr(9);
        bool enable = (arg == "on" || arg == "true");
        agent_->getConfig().maxMode = enable;
        if (output_callback_) output_callback_("Max mode " + std::string(enable ? "enabled" : "disabled") + "\n");
    }
    else if (input.rfind("/deepthinking ", 0) == 0) {
        std::string arg = input.substr(14);
        bool enable = (arg == "on" || arg == "true");
        agent_->getConfig().deepThinking = enable;
        if (output_callback_) output_callback_("Deep thinking " + std::string(enable ? "enabled" : "disabled") + "\n");
    }
    else if (input.rfind("/deepresearch ", 0) == 0) {
        std::string arg = input.substr(14);
        bool enable = (arg == "on" || arg == "true");
        agent_->getConfig().deepResearch = enable;
        if (output_callback_) output_callback_("Deep research " + std::string(enable ? "enabled" : "disabled") + "\n");
    }
    else if (input.rfind("/norefusal ", 0) == 0) {
        std::string arg = input.substr(11);
        bool enable = (arg == "on" || arg == "true");
        agent_->getConfig().noRefusal = enable;
        if (output_callback_) output_callback_("No refusal " + std::string(enable ? "enabled" : "disabled") + "\n");
    }
    else if (input.rfind("/context ", 0) == 0) {
        std::string size_str = input.substr(9);
        size_t size = ParseContextSize(size_str);
        if (size > 0) {
            memory_->SetContextSize(static_cast<MemoryManager::ContextSize>(size));
            if (output_callback_) output_callback_("Context size set to " + size_str + "\n");
        }
    }
    else if (input == "/help") {
        if (output_callback_) output_callback_(GetHelp() + "\n");
    }
    else if (input == "/exit" || input == "exit") {
        if (output_callback_) output_callback_("Exiting...\n");
        running_ = false;
    }
    else {
        // Regular chat processing
        ProcessRegularInput(input);
    }
}

void InteractiveShell::ProcessPluginCommand(const std::string& cmd) {
    std::istringstream iss(cmd);
    std::string action, plugin_id;
    iss >> action >> plugin_id;
    
    VSIXLoader& loader = VSIXLoader::GetInstance();
    
    if (action == "load") {
        std::string path;
        std::getline(iss, path);
        path.erase(0, path.find_first_not_of(" \t"));
        bool result = loader.LoadPlugin(path);
        if (output_callback_) output_callback_(result ? "Plugin loaded\n" : "Failed to load plugin\n");
    }
    else if (action == "unload") {
        bool result = loader.UnloadPlugin(plugin_id);
        if (output_callback_) output_callback_(result ? "Plugin unloaded\n" : "Plugin not found\n");
    }
    else if (action == "enable") {
        bool result = loader.EnablePlugin(plugin_id);
        if (output_callback_) output_callback_(result ? "Plugin enabled\n" : "Plugin not found\n");
    }
    else if (action == "disable") {
        bool result = loader.DisablePlugin(plugin_id);
        if (output_callback_) output_callback_(result ? "Plugin disabled\n" : "Plugin not found\n");
    }
    else if (action == "reload") {
        bool result = loader.ReloadPlugin(plugin_id);
        if (output_callback_) output_callback_(result ? "Plugin reloaded\n" : "Failed to reload\n");
    }
    else if (action == "help") {
        std::string help = loader.GetPluginHelp(plugin_id);
        if (output_callback_) output_callback_(help + "\n");
    }
    else if (action == "list") {
        auto plugins = loader.GetLoadedPlugins();
        std::string list = "Loaded plugins:\n";
        for (auto* plugin : plugins) {
            list += "  " + plugin->id + " (" + plugin->name + ") - " + 
                   (plugin->enabled ? "Enabled" : "Disabled") + "\n";
        }
        if (output_callback_) output_callback_(list);
    }
    else if (action == "config") {
        std::string key, value;
        iss >> key >> value;
        nlohmann::json config;
        config[key] = value;
        bool result = loader.ConfigurePlugin(plugin_id, config);
        if (output_callback_) output_callback_(result ? "Configuration updated\n" : "Failed to configure\n");
    }
    else {
        if (output_callback_) output_callback_("Unknown plugin command: " + action + "\n");
    }
}

void InteractiveShell::ProcessMemoryCommand(const std::string& cmd) {
    std::istringstream iss(cmd);
    std::string action, size_str;
    iss >> action >> size_str;
    
    VSIXLoader& loader = VSIXLoader::GetInstance();
    
    if (action == "load") {
        size_t size = ParseContextSize(size_str);
        if (size > 0) {
            bool result = loader.LoadMemoryModule("memory_" + size_str + ".dll", size);
            if (output_callback_) output_callback_(result ? "Memory module loaded\n" : "Failed to load memory module\n");
        }
    }
    else if (action == "unload") {
        size_t size = ParseContextSize(size_str);
        if (size > 0) {
            bool result = loader.UnloadMemoryModule(size);
            if (output_callback_) output_callback_(result ? "Memory module unloaded\n" : "Failed to unload\n");
        }
    }
    else if (action == "list") {
        auto modules = loader.GetAvailableMemoryModules();
        std::string list = "Available memory modules:\n";
        for (auto size : modules) {
            list += "  " + std::to_string(size) + " tokens\n";
        }
        if (output_callback_) output_callback_(list);
    }
}

size_t InteractiveShell::ParseContextSize(const std::string& size_str) {
    if (size_str == "4k") return 4096;
    if (size_str == "32k") return 32768;
    if (size_str == "64k") return 65536;
    if (size_str == "128k") return 131072;
    if (size_str == "256k") return 262144;
    if (size_str == "512k") return 524288;
    if (size_str == "1m") return 1048576;
    return 0;
}

void InteractiveShell::ProcessRegularInput(const std::string& input) {
    if (!agent_ || !output_callback_) return;
    
    // Apply memory context
    std::string context_aware_input = memory_->ProcessWithContext(input);
    
    // Process with agent
    std::string response = agent_->chat(context_aware_input);
    
    // Auto-correct if enabled
    if (agent_->getConfig().autoCorrect) {
        response = AdvancedFeatures::AutoCorrect(response);
    }
    
    output_callback_(response + "\n");
}

