                    case IDC_SHELL_SEND:
                        {
                            wchar_t buffer[1024];
                            GetWindowTextW(GetDlgItem(hwnd, IDC_SHELL_INPUT), buffer, 1024);
                            std::wstring input(buffer);
                            if (!input.empty()) {
                                std::string utf8_input(input.begin(), input.end());
                                pThis->shell_->SendInput(utf8_input);
                                SetWindowTextW(GetDlgItem(hwnd, IDC_SHELL_INPUT), L"");
                            }
                        }
                        return 0;
                }
                break;
                
            case WM_KEYDOWN:
                if (wParam == 'P' && (GetKeyState(VK_CONTROL) & 0x8000) && (GetKeyState(VK_SHIFT) & 0x8000)) {
                    pThis->OnCommandPalette();
                    return 0;
                }
                break;
        }
    }
    
    return DefWindowProcW(hwnd, uMsg, wParam, lParam);
